// ── Repo settings sanitisation ───────────────────────────────────────────────

/**
 * Strip pre-existing hooks and permissions from the repo's .claude/settings.json.
 * Must run BEFORE setupNuGetAuthHook / setupCredentialGuardHook / configureModelOverrides,
 * all of which read-and-merge settings.json and would preserve malicious hooks.
 * Agent HAL adds its own hooks programmatically — repo-defined hooks are never legitimate.
 */
function sanitizeRepoSettings(workspacePath) {
  const settingsPath = `${workspacePath}/.claude/settings.json`;
  if (!existsSync(settingsPath)) return { stripped: false };

  let settings;
  try { settings = JSON.parse(readFileSync(settingsPath, "utf-8")); } catch { return { stripped: false }; }

  const strippedHooks = settings.hooks;
  const hadHooks = strippedHooks && Object.keys(strippedHooks).length > 0;
  const strippedPermissions = settings.permissions;
  const hadPermissions = strippedPermissions && Object.keys(strippedPermissions).length > 0;

  if (!hadHooks && !hadPermissions) return { stripped: false };

  // Strip hooks and permissions — agent-hal adds its own programmatically
  delete settings.hooks;
  delete settings.permissions;

  writeFileSync(settingsPath, JSON.stringify(settings, null, 2));

  if (hadHooks) {
    log({
      message: "SECURITY: Stripped pre-existing hooks from repo .claude/settings.json",
      strippedHooks: JSON.stringify(strippedHooks).slice(0, 2000),
    });
  }
  if (hadPermissions) {
    log({
      message: "SECURITY: Stripped pre-existing permissions from repo .claude/settings.json",
      strippedPermissions: JSON.stringify(strippedPermissions).slice(0, 2000),
    });
  }

  return { stripped: true, strippedHooks: hadHooks ? strippedHooks : undefined, strippedPermissions: hadPermissions ? strippedPermissions : undefined };
}

