cd /tmp && cat > compare-prompts.mjs << 'SCRIPT'
import { readFileSync } from "fs";

const devRaw = JSON.parse(readFileSync(process.argv[2], "utf-8"));
const prodRaw = JSON.parse(readFileSync(process.argv[3], "utf-8"));

function normalize(items) {
  const map = {};
  for (const item of items) {
    const stage = item.stage?.S;
    const id = item.id?.S;
    const key = `${stage}#${id}`;
    map[key] = {
      stage,
      id,
      seq: Number(item.seq?.N),
      enabled: item.enabled?.BOOL,
      version: Number(item.version?.N),
      content: item.content?.S,
      persona: item.persona?.S || null,
    };
  }
  return map;
}

const dev = normalize(devRaw.Items);
const prod = normalize(prodRaw.Items);

const allKeys = new Set([...Object.keys(dev), ...Object.keys(prod)]);
const diffs = [];

for (const key of [...allKeys].sort()) {
  const d = dev[key];
  const p = prod[key];

  if (!d) {
    diffs.push({ key, status: "PROD ONLY", prod: p });
  } else if (!p) {
    diffs.push({ key, status: "DEV ONLY", dev: d });
  } else {
    // Compare fields
    const fieldDiffs = {};
    if (d.enabled !== p.enabled) fieldDiffs.enabled = { dev: d.enabled, prod: p.enabled };
    if (d.version !== p.version) fieldDiffs.version = { dev: d.version, prod: p.version };
    if (d.seq !== p.seq) fieldDiffs.seq = { dev: d.seq, prod: p.seq };
    if (d.persona !== p.persona) fieldDiffs.persona = { dev: d.persona, prod: p.persona };
    if (d.content !== p.content) {
      fieldDiffs.content = {
        dev: d.content?.slice(0, 200) + (d.content?.length > 200 ? "..." : ""),
        prod: p.content?.slice(0, 200) + (p.content?.length > 200 ? "..." : ""),
      };
    }
    if (Object.keys(fieldDiffs).length > 0) {
      diffs.push({ key, status: "DIFFERS", diffs: fieldDiffs });
    }
  }
}

if (diffs.length === 0) {
  console.log("No differences found. Tables are identical.");
} else {
  console.log(`Found ${diffs.length} difference(s):\n`);
  for (const diff of diffs) {
    console.log(`=== ${diff.key} [${diff.status}] ===`);
    if (diff.status === "DEV ONLY") {
      console.log(`  stage=${diff.dev.stage} id=${diff.dev.id} seq=${diff.dev.seq} enabled=${diff.dev.enabled} v=${diff.dev.version} persona=${diff.dev.persona}`);
      console.log(`  content: ${diff.dev.content?.slice(0, 300)}`);
    } else if (diff.status === "PROD ONLY") {
      console.log(`  stage=${diff.prod.stage} id=${diff.prod.id} seq=${diff.prod.seq} enabled=${diff.prod.enabled} v=${diff.prod.version} persona=${diff.prod.persona}`);
      console.log(`  content: ${diff.prod.content?.slice(0, 300)}`);
    } else {
      for (const [field, vals] of Object.entries(diff.diffs)) {
        console.log(`  ${field}:`);
        console.log(`    DEV:  ${typeof vals.dev === 'string' ? vals.dev : JSON.stringify(vals.dev)}`);
        console.log(`    PROD: ${typeof vals.prod === 'string' ? vals.prod : JSON.stringify(vals.prod)}`);
      }
    }
    console.log();
  }
}

// Summary
console.log(`\nSummary: DEV has ${Object.keys(dev).length} prompts, PROD has ${Object.keys(prod).length} prompts`);
